//! Worker orchestration boundary for future long-running CMT tasks.
//!
//! Future phases can place scan, patch, download, and subprocess orchestration
//! behind this module so slow work stays off the Slint UI thread. Phase 1 keeps
//! it inert and does not create runtimes, channels, tasks, or UI-thread handoffs.

/// No-op worker runtime marker reserved for future background orchestration.
///
/// Constructing this marker starts no Tokio runtime, spawns no tasks, and owns no
/// live worker handles. This preserves SAFE-05 while documenting the seam for
/// later non-blocking work.
#[derive(Debug, Default, Clone, Copy)]
pub struct WorkerRuntime;

//! Injectable desktop open and external-tool launch adapters.
//!
//! UI callbacks should receive [`DesktopActionResult`] values from this module
//! instead of opening dialogs, silently logging failures, or directly launching
//! processes on the Slint event thread.

use std::path::Path;

use crate::platform::{PlatformError, PlatformErrorKind, PlatformOperation};

/// Result value for URL/path open and external-tool launch requests.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DesktopActionResult {
    /// Kind of action that was attempted.
    pub operation: PlatformOperation,
    /// User-selected or adapter-supplied action target.
    pub target: String,
    /// Success or typed failure state.
    pub outcome: DesktopActionOutcome,
    safe_message: String,
}

impl DesktopActionResult {
    /// Creates a successful action result.
    pub fn success(operation: PlatformOperation, target: impl Into<String>) -> Self {
        Self {
            operation,
            target: target.into(),
            outcome: DesktopActionOutcome::Succeeded,
            safe_message: operation.success_message().to_owned(),
        }
    }

    /// Creates a failed action result from a platform error.
    pub fn failure(error: PlatformError) -> Self {
        Self {
            operation: error.operation,
            target: error.target.clone(),
            outcome: DesktopActionOutcome::Failed(error.kind),
            safe_message: error.user_message().to_owned(),
        }
    }

    /// Returns true when the action was started successfully.
    pub const fn is_success(&self) -> bool {
        matches!(self.outcome, DesktopActionOutcome::Succeeded)
    }

    /// Returns the typed failure kind when the action failed.
    pub const fn failure_kind(&self) -> Option<PlatformErrorKind> {
        match self.outcome {
            DesktopActionOutcome::Succeeded => None,
            DesktopActionOutcome::Failed(kind) => Some(kind),
        }
    }

    /// Returns safe user-facing text for status surfaces.
    pub fn safe_message(&self) -> &str {
        &self.safe_message
    }
}

/// Success or typed failure state for a desktop action.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum DesktopActionOutcome {
    /// The adapter successfully handed the action to the OS.
    Succeeded,
    /// The adapter could not perform the action and classified why.
    Failed(PlatformErrorKind),
}

/// Fakeable desktop action boundary.
pub trait DesktopActions {
    /// Opens a URL through the platform desktop handler.
    fn open_url(&self, url: &str) -> DesktopActionResult;

    /// Opens a file or folder through the platform desktop handler.
    fn open_path(&self, path: &Path) -> DesktopActionResult;

    /// Launches an executable tool with arguments.
    fn launch_tool(&self, executable: &Path, args: &[String]) -> DesktopActionResult;
}

/// Production desktop action adapter.
#[derive(Debug, Default, Clone, Copy)]
pub struct RealDesktopActions;

impl RealDesktopActions {
    /// Creates the production desktop action adapter without launching anything.
    pub const fn new() -> Self {
        Self
    }
}

impl DesktopActions for RealDesktopActions {
    fn open_url(&self, url: &str) -> DesktopActionResult {
        open_real_url(url)
    }

    fn open_path(&self, path: &Path) -> DesktopActionResult {
        open_real_path(path)
    }

    fn launch_tool(&self, executable: &Path, args: &[String]) -> DesktopActionResult {
        launch_real_tool(executable, args)
    }
}

#[cfg(not(windows))]
fn open_real_url(url: &str) -> DesktopActionResult {
    DesktopActionResult::failure(PlatformError::unsupported(
        PlatformOperation::OpenUrl,
        url.to_owned(),
    ))
}

#[cfg(not(windows))]
fn open_real_path(path: &Path) -> DesktopActionResult {
    DesktopActionResult::failure(PlatformError::unsupported(
        PlatformOperation::OpenPath,
        path.display().to_string(),
    ))
}

#[cfg(not(windows))]
fn launch_real_tool(executable: &Path, _args: &[String]) -> DesktopActionResult {
    DesktopActionResult::failure(PlatformError::unsupported(
        PlatformOperation::LaunchTool,
        executable.display().to_string(),
    ))
}

#[cfg(windows)]
fn open_real_url(url: &str) -> DesktopActionResult {
    hand_to_windows_shell(PlatformOperation::OpenUrl, url)
}

#[cfg(windows)]
fn open_real_path(path: &Path) -> DesktopActionResult {
    hand_to_windows_shell(PlatformOperation::OpenPath, &path.display().to_string())
}

#[cfg(windows)]
fn hand_to_windows_shell(operation: PlatformOperation, target: &str) -> DesktopActionResult {
    use windows::{
        Win32::UI::{Shell::ShellExecuteW, WindowsAndMessaging::SW_SHOWNORMAL},
        core::{HSTRING, w},
    };

    let target_hstring = HSTRING::from(target);
    let result =
        unsafe { ShellExecuteW(None, w!("open"), &target_hstring, None, None, SW_SHOWNORMAL) };

    if (result.0 as isize) > 32 {
        DesktopActionResult::success(operation, target.to_owned())
    } else {
        DesktopActionResult::failure(PlatformError::command_failed(
            operation,
            target.to_owned(),
            format!("ShellExecuteW failed with code {}", result.0 as isize),
        ))
    }
}

#[cfg(windows)]
fn launch_real_tool(executable: &Path, args: &[String]) -> DesktopActionResult {
    use std::process::Command;

    match Command::new(executable).args(args).spawn() {
        Ok(_) => DesktopActionResult::success(
            PlatformOperation::LaunchTool,
            executable.display().to_string(),
        ),
        Err(error) => DesktopActionResult::failure(PlatformError::from_io(
            PlatformOperation::LaunchTool,
            executable.display().to_string(),
            &error,
        )),
    }
}

#[cfg(test)]
mod tests {
    use std::collections::BTreeMap;

    use super::*;

    #[derive(Debug, Default)]
    struct FakeDesktopActions {
        failures: BTreeMap<(PlatformOperation, String), PlatformErrorKind>,
    }

    impl FakeDesktopActions {
        fn fail(
            mut self,
            operation: PlatformOperation,
            target: impl Into<String>,
            kind: PlatformErrorKind,
        ) -> Self {
            self.failures.insert((operation, target.into()), kind);
            self
        }

        fn run(&self, operation: PlatformOperation, target: String) -> DesktopActionResult {
            if let Some(kind) = self.failures.get(&(operation, target.clone())) {
                DesktopActionResult::failure(PlatformError::new(
                    operation,
                    target,
                    *kind,
                    format!("{} failed.", operation.label()),
                ))
            } else {
                DesktopActionResult::success(operation, target)
            }
        }
    }

    impl DesktopActions for FakeDesktopActions {
        fn open_url(&self, url: &str) -> DesktopActionResult {
            self.run(PlatformOperation::OpenUrl, url.to_owned())
        }

        fn open_path(&self, path: &Path) -> DesktopActionResult {
            self.run(PlatformOperation::OpenPath, path.display().to_string())
        }

        fn launch_tool(&self, executable: &Path, _args: &[String]) -> DesktopActionResult {
            self.run(
                PlatformOperation::LaunchTool,
                executable.display().to_string(),
            )
        }
    }

    #[test]
    fn fake_desktop_actions_return_typed_success_values() {
        let desktop = FakeDesktopActions::default();

        let result = desktop.open_url("https://example.invalid/tool");

        assert!(result.is_success());
        assert_eq!(result.operation, PlatformOperation::OpenUrl);
        assert_eq!(result.target, "https://example.invalid/tool");
        assert_eq!(result.safe_message(), "Opened URL.");
        assert_eq!(result.failure_kind(), None);
    }

    #[test]
    fn fake_desktop_actions_return_typed_failures_without_launching() {
        let desktop = FakeDesktopActions::default().fail(
            PlatformOperation::LaunchTool,
            r"C:\Tools\BSArch.exe",
            PlatformErrorKind::NotFound,
        );

        let result = desktop.launch_tool(Path::new(r"C:\Tools\BSArch.exe"), &[]);

        assert!(!result.is_success());
        assert_eq!(result.operation, PlatformOperation::LaunchTool);
        assert_eq!(result.failure_kind(), Some(PlatformErrorKind::NotFound));
        assert_eq!(result.safe_message(), "Tool launch failed.");
    }

    #[cfg(not(windows))]
    #[test]
    fn real_desktop_actions_are_explicitly_unsupported_off_windows() {
        let desktop = RealDesktopActions::new();

        let url_result = desktop.open_url("https://example.invalid");
        let path_result = desktop.open_path(Path::new("Data"));
        let launch_result = desktop.launch_tool(Path::new("xEdit.exe"), &[]);

        assert_eq!(
            url_result.failure_kind(),
            Some(PlatformErrorKind::UnsupportedPlatform)
        );
        assert_eq!(
            path_result.failure_kind(),
            Some(PlatformErrorKind::UnsupportedPlatform)
        );
        assert_eq!(
            launch_result.failure_kind(),
            Some(PlatformErrorKind::UnsupportedPlatform)
        );
        assert_eq!(
            url_result.safe_message(),
            "URL open is not supported on this platform."
        );
    }
}

//! Injectable process, executable-version, and system-metadata adapters.
//!
//! The reference app inspects parent processes to detect MO2/Vortex, reads file
//! version metadata from executables, and later displays PC specs. This module
//! exposes those operations through fakeable traits and explicit typed failures.

use std::path::{Path, PathBuf};

use crate::{
    domain::discovery::SemanticVersion,
    platform::{PlatformError, PlatformOperation, PlatformResult},
};

/// Single process record from a platform process table snapshot.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ProcessInfo {
    /// Operating-system process identifier.
    pub pid: u32,
    /// Parent process identifier when available.
    pub parent_pid: Option<u32>,
    /// Process executable name, such as `ModOrganizer.exe`.
    pub name: String,
    /// Full executable path when the platform can report it.
    pub executable_path: Option<PathBuf>,
}

impl ProcessInfo {
    /// Creates a typed process record.
    pub fn new(
        pid: u32,
        parent_pid: Option<u32>,
        name: impl Into<String>,
        executable_path: Option<impl Into<PathBuf>>,
    ) -> Self {
        Self {
            pid,
            parent_pid,
            name: name.into(),
            executable_path: executable_path.map(Into::into),
        }
    }
}

/// Executable or DLL version metadata.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct VersionMetadata {
    /// Three-part semantic version used by domain manager contracts.
    pub semantic: SemanticVersion,
    /// Raw platform version string when one was available.
    pub raw: Option<String>,
}

impl VersionMetadata {
    /// Creates version metadata from a semantic version and optional raw string.
    pub fn new(semantic: SemanticVersion, raw: Option<impl Into<String>>) -> Self {
        Self {
            semantic,
            raw: raw.map(Into::into),
        }
    }
}

/// PC specs and operating-system metadata collected behind the platform seam.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct SystemMetadata {
    /// Operating-system family or caption.
    pub os_name: String,
    /// Operating-system version/build when available.
    pub os_version: Option<String>,
    /// CPU architecture reported by Rust for the running binary.
    pub architecture: String,
    /// CPU model/brand when available.
    pub cpu_brand: Option<String>,
    /// Physical memory in bytes when available.
    pub physical_memory_bytes: Option<u64>,
    /// Logical CPU count when available.
    pub logical_cpu_count: Option<usize>,
}

impl SystemMetadata {
    /// Creates system metadata from already-collected values.
    pub fn new(
        os_name: impl Into<String>,
        os_version: Option<impl Into<String>>,
        architecture: impl Into<String>,
        cpu_brand: Option<impl Into<String>>,
        physical_memory_bytes: Option<u64>,
        logical_cpu_count: Option<usize>,
    ) -> Self {
        Self {
            os_name: os_name.into(),
            os_version: os_version.map(Into::into),
            architecture: architecture.into(),
            cpu_brand: cpu_brand.map(Into::into),
            physical_memory_bytes,
            logical_cpu_count,
        }
    }
}

/// Fakeable process and metadata inspection boundary.
pub trait ProcessInspector {
    /// Returns a point-in-time process table snapshot.
    fn list_processes(&self) -> PlatformResult<Vec<ProcessInfo>>;

    /// Reads executable or DLL version metadata, returning `Ok(None)` when absent.
    fn file_version(&self, path: &Path) -> PlatformResult<Option<VersionMetadata>>;

    /// Reads PC specs and operating-system metadata.
    fn system_metadata(&self) -> PlatformResult<SystemMetadata>;
}

/// Production process inspector.
#[derive(Debug, Default, Clone, Copy)]
pub struct RealProcessInspector;

impl RealProcessInspector {
    /// Creates the production process inspector without querying the OS.
    pub const fn new() -> Self {
        Self
    }
}

impl ProcessInspector for RealProcessInspector {
    fn list_processes(&self) -> PlatformResult<Vec<ProcessInfo>> {
        list_real_processes()
    }

    fn file_version(&self, path: &Path) -> PlatformResult<Option<VersionMetadata>> {
        read_real_file_version(path)
    }

    fn system_metadata(&self) -> PlatformResult<SystemMetadata> {
        read_real_system_metadata()
    }
}

#[cfg(not(windows))]
fn list_real_processes() -> PlatformResult<Vec<ProcessInfo>> {
    Err(PlatformError::unsupported(
        PlatformOperation::ListProcesses,
        "process table",
    ))
}

#[cfg(not(windows))]
fn read_real_file_version(path: &Path) -> PlatformResult<Option<VersionMetadata>> {
    Err(PlatformError::unsupported(
        PlatformOperation::ReadVersionMetadata,
        path.display().to_string(),
    ))
}

#[cfg(not(windows))]
fn read_real_system_metadata() -> PlatformResult<SystemMetadata> {
    Err(PlatformError::unsupported(
        PlatformOperation::ReadSystemMetadata,
        "system metadata",
    ))
}

#[cfg(windows)]
fn list_real_processes() -> PlatformResult<Vec<ProcessInfo>> {
    let system = sysinfo::System::new_all();
    let mut processes = system
        .processes()
        .values()
        .map(|process| {
            ProcessInfo::new(
                process.pid().as_u32(),
                process.parent().map(|pid| pid.as_u32()),
                process.name().to_string_lossy(),
                process.exe().map(Path::to_path_buf),
            )
        })
        .collect::<Vec<_>>();

    processes.sort_by(|left, right| {
        left.pid
            .cmp(&right.pid)
            .then_with(|| left.name.cmp(&right.name))
    });
    Ok(processes)
}

#[cfg(windows)]
fn read_real_system_metadata() -> PlatformResult<SystemMetadata> {
    let system = sysinfo::System::new_all();
    let os_name = sysinfo::System::long_os_version()
        .or_else(sysinfo::System::name)
        .unwrap_or_else(|| "Windows".to_owned());
    let cpu_brand = system
        .cpus()
        .first()
        .map(|cpu| cpu.brand().to_owned())
        .filter(|brand| !brand.is_empty());
    let logical_cpu_count = Some(system.cpus().len()).filter(|count| *count > 0);

    Ok(SystemMetadata::new(
        os_name,
        sysinfo::System::os_version(),
        std::env::consts::ARCH,
        cpu_brand,
        Some(system.total_memory()),
        logical_cpu_count,
    ))
}

#[cfg(windows)]
fn read_real_file_version(path: &Path) -> PlatformResult<Option<VersionMetadata>> {
    use std::{ffi::c_void, os::windows::ffi::OsStrExt, ptr};

    use windows::{
        Win32::Storage::FileSystem::{
            GetFileVersionInfoSizeW, GetFileVersionInfoW, VS_FIXEDFILEINFO, VerQueryValueW,
        },
        core::PCWSTR,
    };

    let target = path.display().to_string();
    let wide_path = path
        .as_os_str()
        .encode_wide()
        .chain(std::iter::once(0))
        .collect::<Vec<_>>();
    let mut ignored_handle = 0u32;
    let size =
        unsafe { GetFileVersionInfoSizeW(PCWSTR(wide_path.as_ptr()), Some(&mut ignored_handle)) };
    if size == 0 {
        return Ok(None);
    }

    let mut bytes = vec![0u8; size as usize];
    unsafe {
        GetFileVersionInfoW(
            PCWSTR(wide_path.as_ptr()),
            Some(0),
            size,
            bytes.as_mut_ptr().cast::<c_void>(),
        )
    }
    .map_err(|error| {
        PlatformError::command_failed(
            PlatformOperation::ReadVersionMetadata,
            target.clone(),
            error.message(),
        )
    })?;

    let root_block = "\\"
        .encode_utf16()
        .chain(std::iter::once(0))
        .collect::<Vec<_>>();
    let mut version_ptr: *mut c_void = ptr::null_mut();
    let mut version_len = 0u32;
    let queried = unsafe {
        VerQueryValueW(
            bytes.as_ptr().cast::<c_void>(),
            PCWSTR(root_block.as_ptr()),
            &mut version_ptr,
            &mut version_len,
        )
    };
    if !queried.as_bool() || version_ptr.is_null() {
        return Ok(None);
    }

    let fixed = unsafe { *(version_ptr.cast::<VS_FIXEDFILEINFO>()) };
    let major = ((fixed.dwFileVersionMS >> 16) & 0xffff) as u64;
    let minor = (fixed.dwFileVersionMS & 0xffff) as u64;
    let patch = ((fixed.dwFileVersionLS >> 16) & 0xffff) as u64;
    let private = fixed.dwFileVersionLS & 0xffff;
    let raw = format!("{major}.{minor}.{patch}.{private}");

    Ok(Some(VersionMetadata::new(
        SemanticVersion::new(major, minor, patch),
        Some(raw),
    )))
}

#[cfg(test)]
mod tests {
    use crate::platform::{PlatformErrorKind, PlatformOperation};

    use super::*;

    #[derive(Debug, Clone)]
    struct FakeProcessInspector {
        processes: PlatformResult<Vec<ProcessInfo>>,
        version: PlatformResult<Option<VersionMetadata>>,
        system: PlatformResult<SystemMetadata>,
    }

    impl Default for FakeProcessInspector {
        fn default() -> Self {
            Self {
                processes: Ok(Vec::new()),
                version: Ok(None),
                system: Ok(SystemMetadata::new(
                    "Windows",
                    Some("10.0"),
                    "x86_64",
                    Some("Fake CPU"),
                    Some(16 * 1024 * 1024 * 1024),
                    Some(8),
                )),
            }
        }
    }

    impl ProcessInspector for FakeProcessInspector {
        fn list_processes(&self) -> PlatformResult<Vec<ProcessInfo>> {
            self.processes.clone()
        }

        fn file_version(&self, _path: &Path) -> PlatformResult<Option<VersionMetadata>> {
            self.version.clone()
        }

        fn system_metadata(&self) -> PlatformResult<SystemMetadata> {
            self.system.clone()
        }
    }

    #[test]
    fn fake_process_inspector_supports_manager_detection_inputs() {
        let inspector = FakeProcessInspector {
            processes: Ok(vec![
                ProcessInfo::new(
                    7,
                    Some(3),
                    "ModOrganizer.exe",
                    Some(r"C:\MO2\ModOrganizer.exe"),
                ),
                ProcessInfo::new(9, Some(7), "cmt-rs.exe", Some(r"C:\Tools\cmt-rs.exe")),
            ]),
            version: Ok(Some(VersionMetadata::new(
                SemanticVersion::new(2, 5, 2),
                Some("2.5.2.0"),
            ))),
            ..Default::default()
        };

        let processes = inspector
            .list_processes()
            .expect("fake process list should be available");
        let manager = processes
            .iter()
            .find(|process| process.name == "ModOrganizer.exe")
            .expect("fake MO2 process should be present");
        let version = inspector
            .file_version(manager.executable_path.as_deref().expect("fake exe path"))
            .expect("fake version should be available")
            .expect("fake version metadata should exist");

        assert_eq!(manager.parent_pid, Some(3));
        assert_eq!(version.semantic, SemanticVersion::new(2, 5, 2));
        assert_eq!(version.raw.as_deref(), Some("2.5.2.0"));
    }

    #[test]
    fn fake_process_inspector_returns_typed_system_failures() {
        let inspector = FakeProcessInspector {
            system: Err(PlatformError::new(
                PlatformOperation::ReadSystemMetadata,
                "fake specs",
                PlatformErrorKind::CommandFailed,
                "System metadata read failed.",
            )),
            ..Default::default()
        };

        let error = inspector
            .system_metadata()
            .expect_err("fake system metadata failure should be typed");

        assert_eq!(error.operation, PlatformOperation::ReadSystemMetadata);
        assert_eq!(error.kind, PlatformErrorKind::CommandFailed);
        assert_eq!(error.user_message(), "System metadata read failed.");
    }

    #[cfg(not(windows))]
    #[test]
    fn real_process_operations_are_explicitly_unsupported_off_windows() {
        let inspector = RealProcessInspector::new();

        let process_error = inspector
            .list_processes()
            .expect_err("non-Windows process inspection should be unsupported");
        let version_error = inspector
            .file_version(Path::new("ModOrganizer.exe"))
            .expect_err("non-Windows version metadata should be unsupported");
        let system_error = inspector
            .system_metadata()
            .expect_err("non-Windows system metadata should be unsupported");

        assert_eq!(process_error.kind, PlatformErrorKind::UnsupportedPlatform);
        assert_eq!(version_error.kind, PlatformErrorKind::UnsupportedPlatform);
        assert_eq!(system_error.kind, PlatformErrorKind::UnsupportedPlatform);
        assert_eq!(
            process_error.user_message(),
            "Process inspection is not supported on this platform."
        );
    }
}

//! Platform adapter boundary for operating-system integrations.
//!
//! Discovery, scans, tool launching, and later UI actions should depend on the
//! traits in this module rather than touching the real filesystem, registry,
//! process table, or desktop handlers directly. Real adapters return explicit
//! typed failures and tests can provide fake implementations without requiring a
//! Fallout 4 install, Windows registry state, running mod manager, or visible
//! desktop handler.

use std::{fmt, io};

pub mod desktop;
pub mod filesystem;
pub mod process;
pub mod registry;
pub mod settings_store;

/// Result type returned by platform adapters.
pub type PlatformResult<T> = Result<T, PlatformError>;

/// OS-facing operation that can fail in a typed, user-safe way.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum PlatformOperation {
    /// Read filesystem metadata for a path.
    ReadMetadata,
    /// Read bytes or text from a file.
    ReadFile,
    /// Enumerate direct children of a directory.
    ReadDirectory,
    /// Recursively traverse a directory tree.
    WalkDirectory,
    /// Query a string value from the platform registry.
    ReadRegistry,
    /// Inspect the process table.
    ListProcesses,
    /// Read executable or DLL version metadata.
    ReadVersionMetadata,
    /// Read PC specs or operating-system metadata.
    ReadSystemMetadata,
    /// Open a URL through the desktop handler.
    OpenUrl,
    /// Open a file or folder through the desktop handler.
    OpenPath,
    /// Launch an external tool executable.
    LaunchTool,
}

impl PlatformOperation {
    /// Returns a concise user-safe label for this operation.
    pub const fn label(self) -> &'static str {
        match self {
            Self::ReadMetadata => "Filesystem metadata read",
            Self::ReadFile => "File read",
            Self::ReadDirectory => "Directory read",
            Self::WalkDirectory => "Directory traversal",
            Self::ReadRegistry => "Registry access",
            Self::ListProcesses => "Process inspection",
            Self::ReadVersionMetadata => "Version metadata read",
            Self::ReadSystemMetadata => "System metadata read",
            Self::OpenUrl => "URL open",
            Self::OpenPath => "Path open",
            Self::LaunchTool => "Tool launch",
        }
    }

    /// Returns the success message used by desktop/action adapters.
    pub const fn success_message(self) -> &'static str {
        match self {
            Self::OpenUrl => "Opened URL.",
            Self::OpenPath => "Opened path.",
            Self::LaunchTool => "Launched tool.",
            _ => "Operation completed.",
        }
    }
}

impl fmt::Display for PlatformOperation {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.label())
    }
}

/// Typed adapter failure categories safe for callers to branch on.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum PlatformErrorKind {
    /// Operation is intentionally unavailable on the current platform.
    UnsupportedPlatform,
    /// Requested target was not found.
    NotFound,
    /// The OS denied access to the requested target.
    PermissionDenied,
    /// Caller supplied a malformed target or unsupported input value.
    InvalidInput,
    /// A child process or system command failed.
    CommandFailed,
    /// Adapter output could not be parsed into the typed contract.
    ParseError,
    /// Generic IO failure not covered by a more specific kind.
    Io,
}

impl PlatformErrorKind {
    /// Maps a standard IO error into the nearest public platform failure kind.
    pub fn from_io_error(error: &io::Error) -> Self {
        match error.kind() {
            io::ErrorKind::NotFound => Self::NotFound,
            io::ErrorKind::PermissionDenied => Self::PermissionDenied,
            io::ErrorKind::InvalidInput | io::ErrorKind::InvalidData => Self::InvalidInput,
            _ => Self::Io,
        }
    }
}

/// Typed platform failure with separated safe user text and diagnostic detail.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PlatformError {
    /// Operation that failed.
    pub operation: PlatformOperation,
    /// Adapter-supplied target, such as a path, URL, process query, or registry value.
    pub target: String,
    /// Typed failure category.
    pub kind: PlatformErrorKind,
    user_message: String,
    diagnostic: Option<String>,
}

impl PlatformError {
    /// Creates a platform error from already-classified data.
    pub fn new(
        operation: PlatformOperation,
        target: impl Into<String>,
        kind: PlatformErrorKind,
        user_message: impl Into<String>,
    ) -> Self {
        Self {
            operation,
            target: target.into(),
            kind,
            user_message: user_message.into(),
            diagnostic: None,
        }
    }

    /// Creates an unsupported-platform error for a real adapter operation.
    pub fn unsupported(operation: PlatformOperation, target: impl Into<String>) -> Self {
        Self::new(
            operation,
            target,
            PlatformErrorKind::UnsupportedPlatform,
            format!("{} is not supported on this platform.", operation.label()),
        )
    }

    /// Creates a platform error from an IO failure without exposing raw OS text to users.
    pub fn from_io(
        operation: PlatformOperation,
        target: impl Into<String>,
        error: &io::Error,
    ) -> Self {
        let kind = PlatformErrorKind::from_io_error(error);
        let user_message = match kind {
            PlatformErrorKind::NotFound => format!("{} target was not found.", operation.label()),
            PlatformErrorKind::PermissionDenied => {
                format!(
                    "{} target could not be accessed because permission was denied.",
                    operation.label()
                )
            }
            PlatformErrorKind::InvalidInput => format!("{} target is invalid.", operation.label()),
            PlatformErrorKind::UnsupportedPlatform
            | PlatformErrorKind::CommandFailed
            | PlatformErrorKind::ParseError
            | PlatformErrorKind::Io => format!("{} failed.", operation.label()),
        };

        Self::new(operation, target, kind, user_message).with_diagnostic(error.to_string())
    }

    /// Creates an adapter command failure with diagnostic detail kept separate from user text.
    pub fn command_failed(
        operation: PlatformOperation,
        target: impl Into<String>,
        diagnostic: impl Into<String>,
    ) -> Self {
        Self::new(
            operation,
            target,
            PlatformErrorKind::CommandFailed,
            format!("{} failed.", operation.label()),
        )
        .with_diagnostic(diagnostic)
    }

    /// Creates a parse failure with diagnostic detail kept separate from user text.
    pub fn parse_error(
        operation: PlatformOperation,
        target: impl Into<String>,
        diagnostic: impl Into<String>,
    ) -> Self {
        Self::new(
            operation,
            target,
            PlatformErrorKind::ParseError,
            format!(
                "{} returned data that could not be understood.",
                operation.label()
            ),
        )
        .with_diagnostic(diagnostic)
    }

    /// Adds non-user-facing diagnostic text for logs or tests.
    pub fn with_diagnostic(mut self, diagnostic: impl Into<String>) -> Self {
        self.diagnostic = Some(diagnostic.into());
        self
    }

    /// Returns safe user-facing text for this failure.
    pub fn user_message(&self) -> &str {
        &self.user_message
    }

    /// Returns diagnostic detail suitable for logs, never for modal/dialog text.
    pub fn diagnostic(&self) -> Option<&str> {
        self.diagnostic.as_deref()
    }
}

impl fmt::Display for PlatformError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(
            formatter,
            "{} ({:?} during {})",
            self.user_message, self.kind, self.operation
        )
    }
}

impl std::error::Error for PlatformError {}

