    /// Returns the typed failure kind when the external action failed.
    pub const fn failure_kind(&self) -> Option<PlatformErrorKind> {
        match self.outcome {
            ExternalActionOutcome::Succeeded => None,
            ExternalActionOutcome::Failed(kind) => Some(kind),
        }
